import{_ as t,o as a,c as i,ai as n}from"./chunks/framework.CaiDwmc7.js";const g=JSON.parse('{"title":"Plugin Overview","description":"The Prism Claude Code plugin — pure markdown-based prompt engineering that extends Claude Code with structured 4-phase workflows.","frontmatter":{"title":"Plugin Overview","description":"The Prism Claude Code plugin — pure markdown-based prompt engineering that extends Claude Code with structured 4-phase workflows.","outline":[2,3]},"headers":[],"relativePath":"plugin/index.md","filePath":"plugin/index.md","lastUpdated":1772487797000}'),r={name:"plugin/index.md"};function o(s,e,l,d,u,p){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="part-i-—-claude-plugin-architecture-prompt-engineering" tabindex="-1">Part I — Claude Plugin Architecture (Prompt Engineering) <a class="header-anchor" href="#part-i-—-claude-plugin-architecture-prompt-engineering" aria-label="Permalink to “Part I — Claude Plugin Architecture (Prompt Engineering)”">​</a></h1><p>The Prism Claude Code plugin is the foundation that underpins every platform — the CLI dashboard, VS Code extension, and Electron app all exist to visualize and control workflows that the plugin defines. The plugin itself is <strong>pure markdown-based prompt engineering</strong> with zero build step. It extends Claude Code with structured workflows, specialized agents, and orchestration skills that transform raw AI capability into a disciplined development methodology.</p><h2 id="plugin-overview" tabindex="-1">Plugin Overview <a class="header-anchor" href="#plugin-overview" aria-label="Permalink to “Plugin Overview”">​</a></h2><p>The Prism plugin registers with Claude Code through a conventional directory layout that is automatically discovered at startup. It provides:</p><ul><li><strong>25 commands</strong> — User-invocable operations via <code>/command-name</code> (3,729 lines)</li><li><strong>10 agents</strong> — Specialized subprocesses spawned via <code>Task(subagent_type=&quot;agent-name&quot;)</code> (1,365 lines)</li><li><strong>11 skills</strong> — Auto-activating workflow orchestrators with trigger patterns (1,823 lines)</li><li><strong>4 scripts</strong> — Shell and Python automation (947 lines)</li><li><strong>No hooks or MCP servers</strong> — The plugin relies entirely on prompt engineering, not runtime hooks</li></ul><h2 id="what-makes-it-different" tabindex="-1">What Makes It Different <a class="header-anchor" href="#what-makes-it-different" aria-label="Permalink to “What Makes It Different”">​</a></h2><p>Unlike traditional software plugins that extend functionality through code, Prism extends Claude Code&#39;s behavior through carefully structured natural language instructions. Each <code>.md</code> file is a prompt that shapes how Claude approaches a task — what agents to spawn, what questions to ask, what output format to use, and what behavioral constraints to follow. The prompt engineering is the product.</p>',7)])])}const c=t(r,[["render",o]]);export{g as __pageData,c as default};
